class Solution:
    def minDays(self, n: int) -> int:
        memo = {0: 0, 1: 1}
        def dfs(n):
            if n in memo:
                return memo[n]
            res = 1 + min(n % 2 + dfs(n // 2), n % 3 + dfs(n // 3))
            memo[n] = res
            return res
        return dfs(n)
```

